const estadoAgentes = { cargado:false, cargando:false, error:"", lista:[], estado:null, simulacion:null };
const estadoTexto = s => s === "Disponible" ? "Disponible" : s === "Trabajando" ? "Trabajando" : s === "Esperando" ? "Esperando" : s || "Disponible";
const estadoClase = s => s.includes("Trabajando") ? "warn" : s.includes("Esperando") ? "info" : s.includes("Error") ? "hot" : "ok";
async function cargarAgentes(){
  if(estadoAgentes.cargando || estadoAgentes.cargado) return;
  try{
    estadoAgentes.cargando = true;
    const [lista, estado, simulacion] = await Promise.all([
      fetch(`${API_BASE}/api/agents`).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()}),
      fetch(`${API_BASE}/api/agents/status`).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()}),
      fetch(`${API_BASE}/api/agents/simulate`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({mission:"Coordinar una estrategia editorial original para APP FACTORY VIDEO IA"})}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()})
    ]);
    estadoAgentes.lista = lista; estadoAgentes.estado = estado; estadoAgentes.simulacion = simulacion; estadoAgentes.cargado = true; estadoAgentes.error = "";
  } catch(e) { estadoAgentes.error = e.message; }
  finally { estadoAgentes.cargando = false; if(["director-ai","agents","agents-status","ai-timeline","agent-specialties","agent-performance"].includes(location.hash.replace("#",""))) route(); }
}
function agenteCarga(){cargarAgentes();return `<article class="card"><span class="eyebrow">Agentes IA</span><h3>Conectando con el backend mock</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para ver la empresa de agentes IA.</p>${estadoAgentes.error?`<p class="workflow-error">${estadoAgentes.error}</p>`:badge("Cargando","info")}</article>`}
function tarjetasAgentes(){return estadoAgentes.lista.map(a=>`<article class="agent-card"><div class="agent-head"><span class="agent-orb ${estadoClase(estadoTexto(a.status))}"></span><div><strong>${a.name}</strong><small>${a.specialty}</small></div>${badge(estadoTexto(a.status),estadoClase(estadoTexto(a.status)))}</div><p>${a.objective}</p><div class="agent-stats"><span>Confianza <b>${a.confidence_level}%</b></span><span>Tiempo <b>${a.execution_time_seconds}s</b></span><span>Última <b>${a.last_execution}</b></span></div></article>`).join("")}
function directorIA(){if(!estadoAgentes.cargado)return agenteCarga();if(!estadoProyectos.cargado)cargarProyectos();const director=estadoAgentes.lista.find(a=>a.slug==="director-ai");const modo=estadoAgentes.simulacion.source_mode||estadoProyectos.activo?.mode||"Contenido global";const proyecto=estadoAgentes.simulacion.active_project_name;return `<article class="card source-mode-card ${proyecto?"linked":"global"}"><span class="eyebrow">Decisión del Director IA</span><h3>${modo}</h3><p>${proyecto?`Actualmente trabajando con: ${proyecto}. La IA solo usará fuentes autorizadas.`:"La IA trabaja sin proyecto vinculado y usa el modo de contenido global."}</p></article><article class="card director-command"><span class="eyebrow">Director General IA</span><h3>Una empresa de agentes coordinada por una inteligencia central</h3><p>${director.objective}</p><div class="grid four"><article class="metric-card"><small>Agentes coordinados</small><span class="metric-value">${estadoAgentes.lista.length}</span></article><article class="metric-card"><small>Confianza IA</small><span class="metric-value">${estadoAgentes.simulacion.confidence_score}%</span></article><article class="metric-card"><small>Calidad mock</small><span class="metric-value">${estadoAgentes.simulacion.quality_score}%</span></article><article class="metric-card"><small>Modo</small><span class="metric-value">${modo}</span></article></div><p class="muted">${estadoAgentes.simulacion.director_summary}</p></article><div class="agent-grid">${tarjetasAgentes()}</div>`}
function estadoAgentesVista(){if(!estadoAgentes.cargado)return agenteCarga();return `<article class="card"><span class="eyebrow">Estado de Agentes</span><h3>${estadoAgentes.estado.status}</h3><p>${estadoAgentes.estado.availability}</p><div class="grid three"><article class="metric-card"><small>Tiempo promedio</small><span class="metric-value">${estadoAgentes.estado.average_time_seconds}s</span></article><article class="metric-card"><small>Carga simulada</small><span class="metric-value">${estadoAgentes.estado.load_percentage}%</span></article><article class="metric-card"><small>Disponibilidad</small><span class="metric-value">100%</span></article></div>${estadoAgentes.estado.agents.map(a=>`<div class="agent-status-row"><div><strong>${a.name}</strong><small>${a.availability}. Tiempo promedio ${a.average_time_seconds}s.</small></div>${badge(a.status,estadoClase(a.status))}<div class="progress-track"><div class="progress-fill" style="width:${a.load_percentage}%"></div></div></div>`).join("")}</article>`}
function timelineIA(){if(!estadoAgentes.cargado)return agenteCarga();return `<article class="card"><span class="eyebrow">Timeline IA</span><h3>Misión simulada coordinada por agentes</h3><p>${estadoAgentes.simulacion.mission}</p><div class="decision-timeline">${estadoAgentes.simulacion.timeline.map(x=>`<div class="timeline-item"><time>${x.time}</time><div><strong>${x.agent}</strong><p>${x.action}</p>${badge(`${x.status} · ${x.confidence_level}%`,x.status==="Completado"?"ok":"warn")}</div></div>`).join("")}</div><div class="ready-card card"><h3>${estadoAgentes.simulacion.final_result}</h3><p>${estadoAgentes.simulacion.next_action}</p>${badge("No genera video, audio ni publica","info")}</div></article>`}
function especialidadesIA(){if(!estadoAgentes.cargado)return agenteCarga();const items=[["Investigación","Contexto seguro y hallazgos"],["Tendencias","Señales por país e idioma"],["Narrativa","Historia clara y retenible"],["Creatividad","Estilo visual futuro"],["Guion","Estructura breve y útil"],["SEO","Metadatos responsables"],["Calidad","Cumplimiento y originalidad"],["Aprendizaje","Principios, no copias"],["Publicación","APIs oficiales futuras"],["Analítica","Lectura ejecutiva"]];return `<div class="specialty-grid">${items.map(([a,b])=>`<article class="card specialty-card"><span class="eyebrow">${a}</span><h3>${b}</h3><p>Especialidad preparada para trabajar con datos reales en fases futuras.</p></article>`).join("")}</div>`}
function rendimientoIA(){if(!estadoAgentes.cargado)return agenteCarga();return `<div class="grid four"><article class="metric-card"><small>Confianza promedio</small><span class="metric-value">89%</span></article><article class="metric-card"><small>Misiones mock</small><span class="metric-value">126</span></article><article class="metric-card"><small>Calidad promedio</small><span class="metric-value">92%</span></article><article class="metric-card"><small>Errores</small><span class="metric-value">0</span></article></div><article class="card"><span class="eyebrow">Rendimiento</span><h3>Agentes con mayor confianza</h3>${estadoAgentes.lista.slice().sort((a,b)=>b.confidence_level-a.confidence_level).slice(0,6).map(a=>`<div class="entity-row"><div><span class="entity-title">${a.name}</span><span class="entity-meta">${a.specialty}. ${a.output}</span></div>${badge(`${a.confidence_level}%`,"ok")}</div>`).join("")}</article>`}
function pantallaAgentes(id){return {"director-ai":directorIA,"agents":()=>estadoAgentes.cargado?`<div class="agent-grid">${tarjetasAgentes()}</div>`:agenteCarga(),"agents-status":estadoAgentesVista,"ai-timeline":timelineIA,"agent-specialties":especialidadesIA,"agent-performance":rendimientoIA}[id]()}

const rutasEjecutivas = ["global-audit","executive-radar","executive-competition","executive-popularity","profitability","roi-dashboard","executive-ai","budget-manager","executive-dashboard"];
const estadoEjecutivo = { cargado:false, cargando:false, error:"", auditoria:null, presupuesto:null, dashboard:null };
async function cargarEjecutivo(forzar=false){
  if(estadoEjecutivo.cargando || (estadoEjecutivo.cargado && !forzar)) return;
  try{
    estadoEjecutivo.cargando=true;
    const payload = { topic:"Herramientas de IA para pequeñas empresas", country:"México", language:"Español", niche:"Tecnología", daily_budget_usd:20 };
    const [auditoria, presupuesto, dashboard] = await Promise.all([
      fetch(`${API_BASE}/api/global-intelligence/audit`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()}),
      fetch(`${API_BASE}/api/global-intelligence/budget/optimize`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({daily_budget_usd:20})}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()}),
      fetch(`${API_BASE}/api/global-intelligence/executive-dashboard`).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()})
    ]);
    estadoEjecutivo.auditoria=auditoria; estadoEjecutivo.presupuesto=presupuesto; estadoEjecutivo.dashboard=dashboard; estadoEjecutivo.cargado=true; estadoEjecutivo.error="";
  }catch(e){estadoEjecutivo.error=e.message}
  finally{estadoEjecutivo.cargando=false;if(rutasEjecutivas.includes(location.hash.replace("#",""))) route()}
}
function ejecutivoCarga(){cargarEjecutivo();return `<article class="card"><span class="eyebrow">Inteligencia Ejecutiva</span><h3>Conectando con el Director Ejecutivo IA</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para auditar oportunidades con datos mock.</p>${estadoEjecutivo.error?`<p class="workflow-error">${estadoEjecutivo.error}</p>`:badge("Cargando","info")}</article>`}
function metricasEjecutivas(){const a=estadoEjecutivo.auditoria,d=estadoEjecutivo.dashboard;return `<div class="grid four"><article class="metric-card"><small>Opportunity Score</small><span class="metric-value">${a.opportunity_score}</span><span class="delta">Score global 0-100</span></article><article class="metric-card"><small>Decisión</small><span class="metric-value">${a.executive_decision.decision}</span><span class="delta">Director Ejecutivo IA</span></article><article class="metric-card"><small>ROI estimado</small><span class="metric-value">${a.roi_dashboard.roi_percentage}%</span><span class="delta">Mock financiero</span></article><article class="metric-card"><small>Presupuesto usado</small><span class="metric-value">US$${d.used_budget_usd}</span><span class="delta">Diario simulado</span></article></div>`}
function auditoriaMundial(){const a=estadoEjecutivo.auditoria;return `${metricasEjecutivas()}<article class="card executive-card"><span class="eyebrow">Auditoría Mundial</span><h3>No se produce nada sin evaluación ejecutiva</h3><p>${a.executive_decision.rationale}</p><div class="grid three">${[["Popularidad",a.score_breakdown.popularity_score],["Competencia",a.score_breakdown.competition_score],["Costo",a.score_breakdown.cost_score],["ROI",a.score_breakdown.roi_score],["Riesgo",a.risk_level],["Viralidad",a.viral_analysis.viral_probability]].map(([k,v])=>`<article class="score-card"><span>${k}</span><strong>${v}</strong><div class="progress-track"><div class="progress-fill" style="width:${Math.min(100,Number(v))}%"></div></div></article>`).join("")}</div></article>`}
function radarEjecutivo(){const a=estadoEjecutivo.auditoria;return `<div class="grid two"><article class="card radar-card"><span class="eyebrow">Radar de Oportunidades</span><h3>${a.topic}</h3><div class="radar"><span class="ring r1"></span><span class="ring r2"></span><span class="ring r3"></span><span class="sweep"></span><i class="radar-dot d0"><b>${a.recommended_country.slice(0,2).toUpperCase()}</b></i><i class="radar-dot d1"><b>ROI</b></i><i class="radar-dot d2"><b>${a.opportunity_score}</b></i><i class="radar-dot d3"><b>${a.recommended_language.slice(0,2).toUpperCase()}</b></i></div></article><article class="card"><span class="eyebrow">Selección recomendada</span><h3>${a.recommended_country} · ${a.recommended_language}</h3>${[["País",a.country_selection.reason],["Idioma",a.language_selection.localization_note],["Ventana",a.market_analysis.best_window],["Mercado",a.market_analysis.market_summary]].map(([k,v])=>`<div class="director-row"><span>${k}</span><strong>${v}</strong></div>`).join("")}</article></div>`}
function competenciaEjecutiva(){const c=estadoEjecutivo.auditoria.competition_analysis;return `<article class="card"><span class="eyebrow">Competencia</span><h3>Analizar sin copiar</h3><p>${c.safe_note}</p>${[["Competencia",c.competition],["Saturación",c.saturation],["Nivel",c.competition_level],["Oportunidad",c.opportunity_gap]].map(([k,v])=>`<div class="director-row"><span>${k}</span><strong>${v}</strong></div>`).join("")}</article>`}
function popularidadEjecutiva(){const t=estadoEjecutivo.auditoria.trend_analysis;return `<article class="card"><span class="eyebrow">Popularidad</span><h3>${t.trend_stage}</h3><div class="grid three"><article class="metric-card"><small>Popularidad</small><span class="metric-value">${t.popularity}</span></article><article class="metric-card"><small>Crecimiento</small><span class="metric-value">${t.growth_speed}</span></article><article class="metric-card"><small>Viralidad</small><span class="metric-value">${estadoEjecutivo.auditoria.viral_analysis.viral_probability}</span></article></div>${t.signals.map(x=>`<div class="entity-row"><div><span class="entity-title">${x}</span><span class="entity-meta">Señal mock sin consumir APIs reales.</span></div>${badge("Detectado","ok")}</div>`).join("")}</article>`}
function rentabilidadEjecutiva(){const r=estadoEjecutivo.auditoria.roi_dashboard;return `<article class="card"><span class="eyebrow">Rentabilidad</span><h3>Antes de gastar, la IA estima retorno</h3>${[["Costo IA",`US$${r.ai_cost_usd}`],["Costo video",`US$${r.video_cost_usd}`],["Ingreso estimado",`US$${r.estimated_revenue_usd}`],["Ganancia estimada",`US$${r.estimated_profit_usd}`],["Probabilidad monetización",`${r.monetization_probability}%`],["ROI",`${r.roi_percentage}%`]].map(([k,v])=>`<div class="director-row"><span>${k}</span><strong>${v}</strong></div>`).join("")}</article>`}
function directorEjecutivo(){const a=estadoEjecutivo.auditoria;return `<article class="card ready-card"><span class="eyebrow">Director Ejecutivo IA</span><h3>${a.executive_decision.decision}</h3><p>${a.executive_decision.rationale}</p><div class="quick-actions">${badge(`Score ${a.opportunity_score}`,"ok")}${badge(`Riesgo ${a.risk_level}`,"info")}${badge(a.executive_decision.next_action,"warn")}<button class="primary-btn" data-production-action="create">Enviar a Producción IA</button><button class="ghost-btn" data-go="ai-production-queue">Ver cola</button></div></article>${auditoriaMundial()}`}
function presupuestoEjecutivo(){const b=estadoEjecutivo.presupuesto;return `<article class="card"><span class="eyebrow">Budget Manager IA</span><h3>Presupuesto diario: US$${b.daily_budget_usd}</h3><p>${b.strategy}</p><div class="grid three"><article class="metric-card"><small>Usado</small><span class="metric-value">US$${b.used_budget_usd}</span></article><article class="metric-card"><small>Disponible</small><span class="metric-value">US$${b.remaining_budget_usd}</span></article><article class="metric-card"><small>Aprobados</small><span class="metric-value">${b.selected_videos.length}</span></article></div>${b.selected_videos.map(x=>`<div class="entity-row"><div><span class="entity-title">${x.title}</span><span class="entity-meta">Costo US$${x.estimated_cost_usd}. ROI esperado ${x.expected_roi_percentage}%.</span></div>${badge(`${x.opportunity_score}/100`,"ok")}</div>`).join("")}</article>`}
function tableroEjecutivo(){const d=estadoEjecutivo.dashboard;return `${metricasEjecutivas()}<article class="card"><span class="eyebrow">Executive Dashboard</span><h3>Vista del dueño de la empresa</h3><p>${d.summary}</p><div class="grid three">${[["Canales activos",d.active_channels],["Videos aprobados",d.approved_videos],["Videos rechazados",d.rejected_videos],["Oportunidades",d.detected_opportunities],["País top",d.top_country],["Idioma recomendado",d.recommended_language],["Tema en crecimiento",d.fastest_growing_topic],["Costo IA",`US$${d.ai_cost_usd}`],["ROI",`${d.estimated_roi_percentage}%`]].map(([k,v])=>`<article class="score-card"><span>${k}</span><strong>${v}</strong></article>`).join("")}</div></article>`}
function pantallaEjecutiva(id){if(!estadoEjecutivo.cargado)return ejecutivoCarga();return {"global-audit":auditoriaMundial,"executive-radar":radarEjecutivo,"executive-competition":competenciaEjecutiva,"executive-popularity":popularidadEjecutiva,profitability:rentabilidadEjecutiva,"roi-dashboard":rentabilidadEjecutiva,"executive-ai":directorEjecutivo,"budget-manager":presupuestoEjecutivo,"executive-dashboard":tableroEjecutivo}[id]()}

const rutasProduccionIA = ["ai-production-queue","ai-production-jobs","ai-storyboard","ai-scenes","ai-assets","ai-narration","ai-subtitles","ai-music","ai-render","ai-quality","hall-of-fame","learning-feedback"];
const estadoProduccionIA = { cargado:false, cargando:false, error:"", trabajos:[], cola:null, hall:[], seleccionado:null };
async function apiProduccion(ruta, opciones={}){const r=await fetch(`${API_BASE}${ruta}`,opciones);if(!r.ok)throw new Error(UI.error);return r.json()}
async function cargarProduccionIA(forzar=false){
  if(estadoProduccionIA.cargando || (estadoProduccionIA.cargado && !forzar)) return;
  try{
    estadoProduccionIA.cargando=true;
    const [trabajos, cola, hall] = await Promise.all([
      apiProduccion("/api/production/jobs"),
      apiProduccion("/api/production/queue"),
      apiProduccion("/api/production/hall-of-fame")
    ]);
    estadoProduccionIA.trabajos=trabajos; estadoProduccionIA.cola=cola; estadoProduccionIA.hall=hall; estadoProduccionIA.seleccionado=trabajos[0]||null; estadoProduccionIA.cargado=true; estadoProduccionIA.error="";
  }catch(e){estadoProduccionIA.error=e.message}
  finally{estadoProduccionIA.cargando=false;if(rutasProduccionIA.includes(location.hash.replace("#",""))) route()}
}
function produccionCarga(){cargarProduccionIA();return `<article class="card"><span class="eyebrow">Producción IA</span><h3>Conectando con AI Production Engine</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para ver la línea industrial de producción mock.</p>${estadoProduccionIA.error?`<p class="workflow-error">${estadoProduccionIA.error}</p>`:badge("Cargando","info")}</article>`}
function trabajoActual(){return estadoProduccionIA.seleccionado||estadoProduccionIA.trabajos[0]||{}}
async function accionProduccionIA(accion,id){
  try{
    if(accion==="create"){
      await apiProduccion("/api/production/create",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({topic:"Herramientas de IA para pequeñas empresas",niche:"Tecnología",language:"Español",country:"México",approved_idea:"Explicar por qué una idea necesita auditoría antes de producir",executive_decision:"PRODUCIR",opportunity_score:85})});
    }
    if(accion==="approve" && id) await apiProduccion(`/api/production/${id}/approve`,{method:"POST"});
    if(accion==="reject" && id) await apiProduccion(`/api/production/${id}/reject`,{method:"POST"});
    estadoProduccionIA.cargado=false; await cargarProduccionIA(true); route();
  }catch(e){estadoProduccionIA.error=e.message; route()}
}
function resumenProduccion(){const q=estadoProduccionIA.cola||{};return `<div class="grid four"><article class="metric-card"><small>Total</small><span class="metric-value">${q.total||0}</span></article><article class="metric-card"><small>En producción</small><span class="metric-value">${q.in_production||0}</span></article><article class="metric-card"><small>Aprobados</small><span class="metric-value">${q.approved||0}</span></article><article class="metric-card"><small>Rechazados</small><span class="metric-value">${q.rejected||0}</span></article></div>`}
function colaProduccionIA(){return `${resumenProduccion()}<article class="card"><span class="eyebrow">Cola de Producción</span><h3>De decisión aprobada a video listo para producir</h3><div class="pipeline-flow">${["Auditoría Mundial","Director Ejecutivo IA","Idea aprobada","Guion","Storyboard","Escenas","Assets","Narración","Subtítulos","Música","Efectos","Render","Calidad","Video aprobado"].map((p,i)=>`<div class="flow-step"><span class="flow-index">${String(i+1).padStart(2,"0")}</span><strong>${p}</strong><small>Línea industrial mock</small>${badge(i<13?"Listo":"Pendiente",i<13?"ok":"warn")}</div>`).join("")}</div><button class="primary-btn" data-production-action="create">Crear trabajo mock</button></article>`}
function trabajosProduccionIA(){return `${resumenProduccion()}<article class="card"><span class="eyebrow">Trabajos</span><h3>Producciones activas</h3>${estadoProduccionIA.trabajos.map(j=>`<div class="entity-row"><div><span class="entity-title">${j.topic}</span><span class="entity-meta">${j.country} · ${j.language} · ${j.niche} · Score ${j.opportunity_score}</span></div><div class="quick-actions">${badge(j.status,j.status==="Video aprobado"?"ok":j.status==="Rechazado"?"hot":"info")}<button class="ghost-btn" data-production-action="approve" data-job-id="${j.id}">Aprobar</button><button class="ghost-btn" data-production-action="reject" data-job-id="${j.id}">Rechazar</button></div></div>`).join("")}</article>`}
function storyboardProduccionIA(){const j=trabajoActual();return `<article class="card"><span class="eyebrow">Storyboard</span><h3>${j.approved_idea||"Idea aprobada"}</h3>${(j.storyboard||[]).map((s,i)=>`<div class="timeline-item"><time>${String(i+1).padStart(2,"0")}</time><div><strong>Bloque ${i+1}</strong><p>${s}</p></div></div>`).join("")}</article>`}
function escenasProduccionIA(){const j=trabajoActual();return `<div class="scene-grid">${(j.scenes||[]).map(s=>`<article class="scene-card"><span>${s.id}</span><strong>${s.title}</strong><p>${s.visual_description}</p><small>${s.duration_seconds}s · ${s.camera_direction}</small></article>`).join("")}</div>`}
function assetsProduccionIA(){const j=trabajoActual();return `<article class="card"><span class="eyebrow">Assets</span><h3>Recursos definidos, no generados</h3>${(j.assets||[]).map(a=>`<div class="entity-row"><div><span class="entity-title">${a.asset_type}</span><span class="entity-meta">${a.description}</span></div>${badge(a.status,"ok")}</div>`).join("")}</article>`}
function narracionProduccionIA(){const n=trabajoActual().narration||{};return `<article class="card"><span class="eyebrow">Narración</span><h3>${n.voice||"Voz IA mock"}</h3><p>${n.script||"Narración pendiente."}</p>${[["Tono",n.tone],["Duración",`${n.duration_seconds||0}s`],["Estado",n.status]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b||"Pendiente"}</strong></div>`).join("")}</article>`}
function subtitulosProduccionIA(){const s=trabajoActual().subtitles||{};return `<article class="card"><span class="eyebrow">Subtítulos</span><h3>${s.language||"Idioma pendiente"}</h3>${(s.lines||[]).map(line=>`<div class="entity-row"><div><span class="entity-title">${line}</span><span class="entity-meta">Línea preparada para futura sincronización.</span></div>${badge(s.status||"Pendiente","info")}</div>`).join("")}</article>`}
function musicaProduccionIA(){const m=trabajoActual().music||{};return `<article class="card"><span class="eyebrow">Música</span><h3>${m.style||"Música pendiente"}</h3>${[["Mood",m.mood],["Derechos",m.rights],["Nicho",m.niche],["Estado",m.status]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b||"Pendiente"}</strong></div>`).join("")}</article>`}
function renderProduccionIA(){const r=trabajoActual().render||{};return `<article class="card"><span class="eyebrow">Render</span><h3>${r.status||"Render pendiente"}</h3><div class="grid three"><article class="metric-card"><small>Formato</small><span class="metric-value">${r.format||"9:16"}</span></article><article class="metric-card"><small>Resolución</small><span class="metric-value">${r.resolution||"1080x1920"}</span></article><article class="metric-card"><small>Progreso</small><span class="metric-value">${r.progress||0}%</span></article></div><p class="muted">Mock preparado. No usa FFmpeg ni motores externos todavía.</p></article>`}
function calidadProduccionIA(){const q=trabajoActual().quality_report||{};const checks=[["Storyboard completo",q.storyboard_complete],["Narración disponible",q.narration_available],["Assets definidos",q.assets_defined],["Subtítulos preparados",q.subtitles_prepared],["Música seleccionada",q.music_selected],["Render listo",q.render_ready]];return `<article class="card"><span class="eyebrow">Control de Calidad</span><h3>${q.approved?"Video aprobado para producción futura":"No aprobar todavía"}</h3><div class="grid three">${checks.map(([a,b])=>`<article class="score-card"><span>${a}</span><strong>${b?"OK":"Falta"}</strong>${badge(b?"Aprobado":"Bloqueado",b?"ok":"hot")}</article>`).join("")}</div><div class="ready-card card"><h3>Score mínimo</h3><p>Score actual: ${q.quality_score||0}/100. Mínimo requerido: 85.</p>${badge(q.approved?"Puede aprobarse":"No aprobar",q.approved?"ok":"hot")}</div></article>`}
function hallProduccionIA(){return `<article class="card"><span class="eyebrow">Hall of Fame</span><h3>Principios de alto rendimiento</h3><p class="muted">No se copian contenidos. Solo se guardan patrones generales para mejorar futuras producciones.</p>${estadoProduccionIA.hall.map(h=>`<div class="entity-row"><div><span class="entity-title">${h.topic}</span><span class="entity-meta">${h.country} · ${h.language} · ${h.niche} · ${h.duration_seconds}s · ${h.success_reason}</span></div>${badge(`${h.roi} ROI`,"ok")}</div>`).join("")}</article>`}
function aprendizajeProduccionIA(){const f=trabajoActual().learning_feedback||{};return `<article class="card"><span class="eyebrow">Learning Feedback</span><h3>Aprender para producir mejor</h3>${["what_worked","what_did_not_work","what_to_improve","future_recommendations"].map(k=>`<div class="entity-row"><div><span class="entity-title">${k.replaceAll("_"," ")}</span><span class="entity-meta">${(f[k]||[]).join(" · ")||"Pendiente"}</span></div>${badge("Principio","info")}</div>`).join("")}<p class="muted">${f.principle||"La IA memoriza principios generales, no videos."}</p></article>`}
function pantallaProduccionIA(id){if(!estadoProduccionIA.cargado)return produccionCarga();return {"ai-production-queue":colaProduccionIA,"ai-production-jobs":trabajosProduccionIA,"ai-storyboard":storyboardProduccionIA,"ai-scenes":escenasProduccionIA,"ai-assets":assetsProduccionIA,"ai-narration":narracionProduccionIA,"ai-subtitles":subtitulosProduccionIA,"ai-music":musicaProduccionIA,"ai-render":renderProduccionIA,"ai-quality":calidadProduccionIA,"hall-of-fame":hallProduccionIA,"learning-feedback":aprendizajeProduccionIA}[id]()}

const estadoProyectos = { cargado:false, cargando:false, error:"", lista:[], activo:null, detalle:null, soportados:null };
const rutasProyecto = ["projects","create-project","project-library","project-documents","active-project","project-sources","content-brain","director-ai","ai-timeline"];
async function apiProyecto(ruta, opciones={}){const r=await fetch(`${API_BASE}${ruta}`,opciones);if(!r.ok)throw new Error(UI.error);if(r.status===204)return null;return r.json()}
async function cargarProyectos(forzar=false){
  if(estadoProyectos.cargando || (estadoProyectos.cargado && !forzar)) return;
  try{
    estadoProyectos.cargando=true;
    const [lista, activo, soportados] = await Promise.all([apiProyecto("/api/projects"), apiProyecto("/api/projects/active"), apiProyecto("/api/projects/supported-sources")]);
    estadoProyectos.lista=lista; estadoProyectos.activo=activo; estadoProyectos.soportados=soportados;
    const base = activo.active_project || lista[0];
    estadoProyectos.detalle = base ? await apiProyecto(`/api/projects/${base.id}`) : null;
    estadoProyectos.cargado=true; estadoProyectos.error="";
  }catch(e){estadoProyectos.error=e.message}
  finally{estadoProyectos.cargando=false;if(rutasProyecto.includes(location.hash.replace("#",""))) route()}
}
function proyectoCarga(){cargarProyectos();return `<article class="card"><span class="eyebrow">Proyectos</span><h3>Conectando biblioteca de fuentes</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para usar proyectos opcionales.</p>${estadoProyectos.error?`<p class="workflow-error">${estadoProyectos.error}</p>`:badge("Cargando","info")}</article>`}
function modoProyectoCard(){if(!estadoProyectos.cargado)cargarProyectos();const activo=estadoProyectos.activo;const global=!activo?.active_project;return `<article class="card source-mode-card ${global?"global":"linked"}"><span class="eyebrow">Modo de trabajo IA</span><h3>${global?"Contenido global":"Proyecto vinculado"}</h3><p>${global?"La IA trabaja sin proyecto y analiza oportunidades globales/locales simuladas.":`Actualmente trabajando con: ${activo.active_project.name}. Solo se usarán fuentes autorizadas.`}</p><div class="quick-actions"><button class="ghost-btn" data-project-action="deactivate">Modo global</button><button class="primary-btn" data-go="active-project">Ver proyecto activo</button></div></article>`}
function listaProyectos(){if(!estadoProyectos.cargado)return proyectoCarga();return `${modoProyectoCard()}<div class="project-grid">${estadoProyectos.lista.map(p=>`<article class="card project-card"><span class="eyebrow">${p.project_type}</span><h3>${p.name}</h3><p>${p.description}</p><div class="style-meta"><span>${p.primary_language}</span><span>${p.country}</span><span>${p.status}</span></div><div class="quick-actions"><button class="primary-btn" data-project-action="activate" data-project-id="${p.id}">Activar</button><button class="ghost-btn" data-project-action="open" data-project-id="${p.id}">Ver documentos</button></div></article>`).join("")}</div>`}
function crearProyecto(){return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Crear Proyecto</span><h3>Nuevo proyecto opcional</h3><p class="muted">La plataforma funciona perfecto sin proyectos. Activa uno solo cuando quieras usar información autorizada.</p><div class="form-grid"><div class="field"><label>Nombre</label><input id="projectName" value="Proyecto Cliente ABC" /></div><div class="field"><label>Idioma principal</label><input id="projectLanguage" value="Español" /></div><div class="field"><label>País</label><input id="projectCountry" value="Chile" /></div><div class="field"><label>Tipo de proyecto</label><select id="projectType">${["Empresa","Marca","Libro","Novela","Serie","Curso","Producto","Cliente","Canal","Otro"].map(x=>`<option>${x}</option>`).join("")}</select></div><div class="field workflow-span"><label>Descripción</label><input id="projectDescription" value="Biblioteca autorizada para crear contenido de marca con contexto propio." /></div></div><button class="primary-btn" data-project-action="create">Crear proyecto</button></article>`}
function bibliotecaProyecto(){if(!estadoProyectos.cargado)return proyectoCarga();const detalle=estadoProyectos.detalle;return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Biblioteca</span><h3>Arrastra archivos para registrarlos</h3><p class="muted">PDF, DOCX, TXT, Markdown, CSV, JSON, HTML, PNG, JPG, WEBP, MP4 y MP3. No se procesan todavía.</p><div class="dropzone" id="projectDropzone"><strong>Arrastra archivos aquí</strong><span>o haz clic para simular documentos ficticios</span></div></article>${documentosProyecto(detalle)}`}
function documentosProyecto(detalle=estadoProyectos.detalle){if(!estadoProyectos.cargado)return proyectoCarga();if(!detalle&&estadoProyectos.lista[0]){apiProyecto(`/api/projects/${estadoProyectos.lista[0].id}`).then(d=>{estadoProyectos.detalle=d;route()});return `${modoProyectoCard()}<article class="card"><h3>Cargando documentos</h3><p class="muted">Preparando biblioteca del proyecto.</p></article>`}if(!detalle)return `${modoProyectoCard()}<article class="card"><h3>Sin proyecto</h3><p class="muted">Crea un proyecto para registrar documentos opcionales.</p></article>`;return `<article class="card"><span class="eyebrow">Documentos</span><h3>${detalle.project.name}</h3>${detalle.documents.length?tabla(["Nombre","Tipo","Peso","Estado","Fecha"],detalle.documents.map(d=>[d.source_file.filename,d.source_file.file_type,`${Math.max(1,Math.round(d.source_file.size_bytes/1024))} KB`,badge(d.source_file.status,d.authorized_for_ai?"ok":"warn"),new Date(d.source_file.uploaded_at).toLocaleDateString("es-CL")])):`<p class="muted">Aún no hay documentos registrados.</p>`}<div class="quick-actions"><button class="primary-btn" data-project-action="fake-docs">Subir documentos ficticios</button><button class="ghost-btn" data-go="project-library">Ir a biblioteca</button></div></article>`}
function proyectoActivo(){if(!estadoProyectos.cargado)return proyectoCarga();const activo=estadoProyectos.activo;return `${modoProyectoCard()}<article class="card active-project-card"><span class="eyebrow">Proyecto Activo</span><h3>Actualmente trabajando con:</h3><div class="active-choice"><span class="choice-dot ${activo.active_project?"":"selected"}"></span><strong>Ningún proyecto</strong><small>Modo global</small></div>${activo.active_project?`<div class="active-choice selected"><span class="choice-dot selected"></span><strong>${activo.active_project.name}</strong><small>${activo.active_project.project_type} · ${activo.active_project.country} · ${activo.active_project.primary_language}</small></div>`:""}<p class="muted">${activo.message}</p><div class="quick-actions"><button class="ghost-btn" data-project-action="deactivate">Volver al modo global</button><button class="primary-btn" data-go="projects">Elegir proyecto</button></div></article>`}
function fuentesProyecto(){if(!estadoProyectos.cargado)return proyectoCarga();const detalle=estadoProyectos.detalle;return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Fuentes soportadas</span><h3>Arquitectura preparada</h3><div class="source-chip-grid">${estadoProyectos.soportados.supported_document_types.map(x=>`<span>${x}</span>`).join("")}</div><p class="muted">${estadoProyectos.soportados.note}</p></article>${detalle?tabla(["Fuente","Tipo","Alcance"],detalle.sources.map(s=>[s.name,s.source_type,s.authorized_scope])):""}`}
async function accionProyecto(accion,id){try{if(accion==="create"){const payload={name:document.getElementById("projectName").value,description:document.getElementById("projectDescription").value,primary_language:document.getElementById("projectLanguage").value,country:document.getElementById("projectCountry").value,project_type:document.getElementById("projectType").value};await apiProyecto("/api/projects",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});location.hash="projects"}if(accion==="activate"){await apiProyecto(`/api/projects/${id}/activate`,{method:"POST"})}if(accion==="deactivate"){await apiProyecto("/api/projects/deactivate",{method:"POST"})}if(accion==="open"){const detail=await apiProyecto(`/api/projects/${id}`);estadoProyectos.detalle=detail;location.hash="project-documents";return}if(accion==="fake-docs"){const project=(estadoProyectos.activo?.active_project||estadoProyectos.lista[0]);if(project){for(const doc of [{filename:"brief-marca.pdf",file_type:"PDF",size_bytes:245000},{filename:"guia-tono.md",file_type:"Markdown",size_bytes:32000},{filename:"datos-campana.csv",file_type:"CSV",size_bytes:88000}]){await apiProyecto(`/api/projects/${project.id}/documents`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(doc)})}}}estadoProyectos.cargado=false;estadoAgentes.cargado=false;await cargarProyectos(true);renderScreen(location.hash.replace("#","")||"projects")}catch(e){estadoProyectos.error=e.message;renderScreen(location.hash.replace("#","")||"projects")}}
function pantallaProyectos(id){return {"projects":listaProyectos,"create-project":crearProyecto,"project-library":bibliotecaProyecto,"project-documents":()=>documentosProyecto(),"active-project":proyectoActivo,"project-sources":fuentesProyecto}[id]()}
const estadoFlujo = { estado:"sin iniciar", error:"", workflowId:"", canal:null, oportunidad:null, decisionEjecutiva:null, ideas:[], ideaElegida:null, hooks:[], hookElegido:null, historia:null, plan:null, listo:null, progreso:{} };
function badge(t,c=""){return `<span class="badge ${c}">${t}</span>`}
function titulo(id){return (pantallas.find(p=>p.id===id)||{label:"Panel principal"}).label}
function ayuda(id){return `<article class="card module-help"><span class="eyebrow">Ayuda rápida</span><h3>${titulo(id)}</h3><p>${ayudas[id]||"Esta sección te ayuda a tomar mejores decisiones."}</p></article>`}
function tabla(cols,rows){return `<article class="table-card"><table class="table"><thead><tr>${cols.map(c=>`<th>${c}</th>`).join("")}</tr></thead><tbody>${rows.map(r=>`<tr>${r.map(x=>`<td>${x}</td>`).join("")}</tr>`).join("")}</tbody></table></article>`}
function metricas(){return `<div class="grid metrics">${datos.metricas.map(([a,b,c])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">${c}</span></article>`).join("")}</div>`}
function mundo(){return `<article class="card world-panel"><span class="eyebrow">Mapa de señales</span><h3>Oportunidades por país, idioma y nicho</h3><p class="muted">Vista simulada para entender dónde conviene crear contenido.</p><div class="world-map"><i class="arc" style="left:18%;top:40%;width:220px;transform:rotate(-10deg)"></i><i class="arc" style="left:34%;top:56%;width:260px;transform:rotate(-20deg)"></i><span class="signal" style="left:18%;top:38%"></span><span class="signal green" style="left:31%;top:61%"></span><span class="signal amber" style="left:55%;top:34%"></span><span class="signal green" style="left:72%;top:53%"></span><span class="world-label">MUNDO</span></div></article>`}
function estado(){return `<article class="card"><span class="eyebrow">Estado</span><h3>Operación clara y segura</h3>${[["Backend","Conectado en modo local","OK"],["IA real","Pendiente para fases futuras","Planificado"],["Publicación","Sin envíos reales","Seguro"],["Contenido","Demostración responsable","Activo"]].map(([a,b,c])=>`<div class="status-row"><div><span class="status-name">${a}</span><span class="status-meta">${b}</span></div>${badge(c,c==="OK"||c==="Activo"?"ok":"info")}</div>`).join("")}</article>`}
function inicio(){return `<section class="welcome-panel"><span class="eyebrow">AppFactoryChile</span><h2>Bienvenido a APP FACTORY VIDEO IA</h2><p>¿Qué deseas hacer hoy?</p><div class="quick-actions"><button class="primary-btn" data-go="channels">Crear un canal</button><button class="primary-btn" data-go="mvp-workflow">Crear contenido</button><button class="ghost-btn" data-go="projects">Continuar proyecto</button><button class="ghost-btn" data-go="videos">Biblioteca</button></div></section>${metricas()}<div class="grid two">${mundo()}${estado()}</div>`}
function radar(){return `<article class="card radar-card"><span class="eyebrow">Radar</span><h3>Temas con mayor oportunidad</h3><div class="radar"><span class="ring r1"></span><span class="ring r2"></span><span class="ring r3"></span><span class="sweep"></span><i class="radar-dot d0"><b>MX</b></i><i class="radar-dot d1"><b>BR</b></i><i class="radar-dot d2"><b>CL</b></i><i class="radar-dot d3"><b>ES</b></i></div></article>`}
function ideas(){return `<article class="card"><span class="eyebrow">Laboratorio de Ideas</span><h3>Ideas antes de producir</h3>${datos.ideas.map(([a,b,c,d])=>`<div class="entity-row"><div><span class="entity-title">${a}</span><span class="entity-meta">Emoción: ${c}. Potencial: ${d}.</span></div>${badge(`${b}/100`,"ok")}</div>`).join("")}</article>`}
function hooks(){return `<article class="card"><span class="eyebrow">Constructor de Hooks</span><h3>Compara inicios posibles</h3><div class="hook-stack">${datos.hooks.map(([a,b])=>`<div class="hook-card"><strong>${a}</strong><span>${b}</span></div>`).join("")}</div></article>`}
function historia(){return `<article class="card director-panel"><span class="eyebrow">Director de Historias</span><h3>Estrategia narrativa recomendada</h3>${[["Objetivo","Explicar una oportunidad de forma simple y útil."],["Narrador","Voz natural, cercana y experta."],["Personaje","Persona realista enfrentando un problema concreto."],["Escenario","Ambiente visual limpio y reconocible."],["Tono","Claro, curioso y responsable."],["Duración","38 segundos."],["Estilo","Oscuro premium con subtítulos dinámicos."]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function plan(){return `<article class="card"><span class="eyebrow">Plan de Producción</span><h3>Cómo debería verse el video</h3>${[["Narrador","Natural y confiable"],["Tipo de voz","Cálida, clara y segura"],["Formato","Vertical 9:16"],["Plataformas","Shorts, Reels y TikTok"],["Música","Moderna, suave y sin derechos"],["Iluminación","Contraste premium"],["Cámara","Movimientos lentos y cortes limpios"],["Color","Base oscura con acentos cian"],["Ritmo","Inicio rápido, explicación clara y cierre breve"]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function aprendizaje(){return `<div class="grid four">${[["Hooks probados","1.284"],["Ideas analizadas","8.420"],["Países aprendiendo","38"],["Mejoras detectadas","126"]].map(([a,b])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">Aprendizaje acumulado</span></article>`).join("")}</div><article class="card"><h3>Recomendaciones aprendidas</h3>${["Las introducciones cortas retienen mejor.","Los ejemplos locales aumentan comentarios.","La utilidad clara supera al volumen de publicaciones.","La narración cálida funciona mejor para contenido educativo."].map(t=>`<div class="entity-row"><div><span class="entity-title">${t}</span><span class="entity-meta">Principio general, no copia de contenido.</span></div>${badge("Aprendido","ok")}</div>`).join("")}</article>`}
function flujoContenido(){const pasos=["Oportunidad","Investigación","Ideas","Ranking","Hook","Historia","Guion gráfico","Plan","Listo"];return `<article class="card"><span class="eyebrow">Flujo de Contenido</span><h3>De la oportunidad al contenido listo</h3><div class="pipeline-flow">${pasos.map((p,i)=>`<div class="flow-step"><span class="flow-index">${String(i+1).padStart(2,"0")}</span><strong>${p}</strong><small>Responsable: IA editorial</small>${badge("Preparado","ok")}</div>`).join("")}</div></article>`}
function proceso(){return `<article class="card"><span class="eyebrow">Proceso del Video</span><h3>Recorrido completo</h3><div class="decision-timeline">${["Idea","Investigación","Guion","Guion gráfico","Narración","Subtítulos","Render","Programación","Analítica","Aprendizaje"].map((p,i)=>`<div class="timeline-item"><time>${String(i+1).padStart(2,"0")}</time><div><strong>${p}</strong><p>Etapa preparada para fases futuras.</p></div></div>`).join("")}</div></article>`}
function produccion(){return `<article class="card"><span class="eyebrow">Producción en Tiempo Real</span><h3>Cola simulada</h3>${["Idea en revisión","Hook seleccionado","Guion gráfico preparado","Plan de producción listo"].map((p,i)=>`<div class="queue-row"><div><span class="entity-title">Contenido ${String(i+1).padStart(3,"0")}</span><span class="entity-meta">${p}</span><div class="progress-track"><div class="progress-fill" style="width:${45+i*15}%"></div></div></div>${badge("Demostración","info")}</div>`).join("")}</article>`}
function pantalla(id){if(["projects","create-project","project-library","project-documents","active-project","project-sources"].includes(id))return `${ayuda(id)}${pantallaProyectos(id)}`;if(rutasProduccionIA.includes(id))return `${ayuda(id)}${pantallaProduccionIA(id)}`;if(rutasEjecutivas.includes(id))return `${ayuda(id)}${pantallaEjecutiva(id)}`;if(["director-ai","agents","agents-status","ai-timeline","agent-specialties","agent-performance"].includes(id))return `${ayuda(id)}${pantallaAgentes(id)}`;const contenido={"global-intelligence":`${mundo()}${tabla(["País","Tema","Idioma","Competencia","Demanda","Horario","Nivel"],datos.oportunidades)}`,"opportunity-radar":`${radar()}${tabla(["País","Nicho","Idioma","Competencia","Potencial","Hora","Nivel"],datos.oportunidades)}`,"learning-engine":aprendizaje(),"story-director":historia(),"idea-lab":ideas(),"hook-builder":hooks(),"content-brain":`${modoProyectoCard()}<div class="grid two"><article class="card"><span class="eyebrow">Cerebro de Contenido</span><h3>Antes de crear, consulta al Director Ejecutivo IA</h3><p>Solo si la auditoría recomienda producir, el sistema continúa hacia ideas, hooks y estrategia narrativa.</p>${badge("Conectado","info")}</article>${ideas()}</div>`,"content-pipeline":flujoContenido(),"production-plan":plan(),"full-video-journey":proceso(),calendar:tabla(["Zona","País","Idioma","Hora ideal","Pendientes"],[["América","México","Español","13:00","12"],["Europa","España","Español","21:00","8"],["Brasil","Brasil","Portugués","08:00","10"]]),monetization:metricas(),"video-factory-live":produccion(),"digital-factory":`<div class="grid two">${produccion()}${flujoContenido()}</div>`,channels:tabla(["Canal","País","Idioma","Nicho","Estado"],datos.canales.map(r=>[r[0],r[1],r[2],r[3],badge(r[4],r[4]==="Activo"?"ok":"warn")])),settings:`<article class="card"><span class="eyebrow">Configuración</span><h3>Preferencias iniciales</h3><div class="form-grid">${["Idioma de la interfaz","Zona horaria","Modo de revisión","Publicación automática","Proveedor IA","Cumplimiento"].map(t=>`<div class="field"><label>${t}</label><input readonly value="Preparado para configurar" /></div>`).join("")}</div></article>`,apis:tabla(["Servicio","Uso futuro","Estado"],[["YouTube","Publicación y métricas oficiales",badge("Pendiente","warn")],["Instagram","Reels y métricas oficiales",badge("Pendiente","warn")],["Facebook","Video y páginas",badge("Pendiente","warn")],["TikTok","Publicación oficial",badge("Pendiente","warn")]]),"mission-control":`${metricas()}<div class="grid two">${estado()}${produccion()}</div>`,system:`${estado()}${metricas()}`,company:`<article class="card"><span class="eyebrow">Empresa matriz</span><h3>AppFactoryChile</h3><p>Correo principal: appfactorychile@gmail.com</p><p class="muted">Proyecto oficial: APP FACTORY VIDEO IA.</p></article>`,projects:tabla(["Proyecto","Canal","Estado","Último paso"],[["IA para pymes","Futuro Latino IA",badge("En curso","info"),"Plan de producción"],["Ahorro energético","Brasil Solar",badge("Borrador","warn"),"Ideas"]]),videos:`<div class="video-grid">${["Idea","Guion","Guion gráfico","Plan","Proyecto","Canal","Hook","Informe"].map((t,i)=>`<article class="card video-card"><div class="thumb">${String(i+1).padStart(2,"0")}</div><div class="video-card-body"><h3>${t}</h3><p class="muted">Elemento preparado en modo demostración.</p>${badge("Biblioteca","info")}</div></article>`).join("")}</div>`,agents:tabla(["Agente","Función","Estado"],[["Analista IA","Detecta oportunidades",badge("Activo","ok")],["Guionista IA","Prepara historias",badge("Activo","ok")],["Editor IA","Planifica producción",badge("Planificado","info")]])};return `${ayuda(id)}${contenido[id]||`<article class="card"><h3>${titulo(id)}</h3><p>Sección preparada para siguientes fases.</p></article>`}`}
function postFlujo(ruta,cuerpo){return fetch(`${API_BASE}${ruta}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(cuerpo)}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()})}
function sync(r){estadoFlujo.workflowId=r.workflow_id||estadoFlujo.workflowId;estadoFlujo.progreso=r.progress||estadoFlujo.progreso;estadoFlujo.estado="listo";estadoFlujo.error=""}
function datosCanal(){const v=id=>document.getElementById(id)?.value.trim()||"";const modo=document.querySelector('input[name="workflowMode"]:checked')?.value||"manual";return{name:v("wfName"),country:v("wfCountry"),language:v("wfLanguage"),niche:v("wfNiche"),description:v("wfDescription"),daily_video_count:Number(v("wfDailyVideos")||8),platforms:v("wfPlatforms").split(",").map(x=>x.trim()).filter(Boolean),mode:modo}}
async function accionFlujo(accion,p={}){try{estadoFlujo.estado="cargando";estadoFlujo.error="";renderScreen("mvp-workflow");let r;if(accion==="create-channel"){r=await postFlujo("/api/workflow/create-channel",datosCanal());sync(r);estadoFlujo.canal=r.channel}if(accion==="analyze-opportunity"){r=await postFlujo("/api/workflow/analyze-opportunity",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.oportunidad=r;estadoFlujo.decisionEjecutiva=r.executive_decision}if(accion==="generate-ideas"){r=await postFlujo("/api/workflow/generate-ideas",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.ideas=r.ideas}if(accion==="choose-idea"){r=await postFlujo("/api/workflow/choose-idea",{workflow_id:estadoFlujo.workflowId,idea_id:p.ideaId});sync(r);estadoFlujo.ideaElegida=r.selected_idea}if(accion==="generate-hooks"){r=await postFlujo("/api/workflow/generate-hooks",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.hooks=r.hooks}if(accion==="choose-hook"){r=await postFlujo("/api/workflow/choose-hook",{workflow_id:estadoFlujo.workflowId,hook_id:p.hookId});sync(r);estadoFlujo.hookElegido=r.selected_hook}if(accion==="generate-story"){r=await postFlujo("/api/workflow/generate-story",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.historia=r}if(accion==="generate-production-plan"){r=await postFlujo("/api/workflow/generate-production-plan",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.plan=r}if(accion==="ready-to-generate"){r=await postFlujo("/api/workflow/ready-to-generate",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.listo=r}renderScreen("mvp-workflow")}catch(e){estadoFlujo.estado="error";estadoFlujo.error=e.message;renderScreen("mvp-workflow")}}
function barra(){const pasos=[["channel","Canal"],["opportunity","Oportunidad"],["ideas","Ideas"],["idea_selected","Idea"],["hooks","Hook"],["storyboard","Guion gráfico"],["production","Producción"],["ready","Listo"]];return `<article class="card workflow-progress"><span class="eyebrow">Flujo guiado</span><h3>Avanza paso a paso</h3><div class="workflow-steps">${pasos.map(([k,l])=>`<span class="${estadoFlujo.progreso[k]?"done":""}">${l} ${estadoFlujo.progreso[k]?"✓":""}</span>`).join("")}</div>${estadoFlujo.error?`<p class="muted workflow-error">${estadoFlujo.error}</p>`:""}</article>`}
function formCanal(){return `<article class="card"><span class="eyebrow">Paso 1</span><h3>Crear canal</h3><div class="form-grid"><div class="field"><label>Nombre</label><input id="wfName" value="Futuro Latino IA" /></div><div class="field"><label>País</label><input id="wfCountry" value="México" /></div><div class="field"><label>Idioma</label><input id="wfLanguage" value="Español" /></div><div class="field"><label>Nicho</label><input id="wfNiche" value="Tecnología" /></div><div class="field"><label>Videos diarios</label><input id="wfDailyVideos" type="number" value="8" /></div><div class="field"><label>Plataformas</label><input id="wfPlatforms" value="YouTube Shorts, Instagram Reels, TikTok" /></div><div class="field workflow-span"><label>Descripción</label><input id="wfDescription" value="Herramientas de IA para pequeñas empresas" /></div><div class="field"><label>Modo</label><div class="mode-toggle"><label><input type="radio" name="workflowMode" value="automatic" /> Automático</label><label><input type="radio" name="workflowMode" value="manual" checked /> Manual</label></div></div></div><button class="primary-btn" data-workflow-action="create-channel">Guardar canal</button></article>`}
function ideasFlujo(){return estadoFlujo.ideas.map((x,i)=>`<article class="workflow-choice ${estadoFlujo.ideaElegida?.id===x.id?"selected":""}"><strong>${["La razón oculta por la que esta herramienta importa ahora","Cómo ahorrar una hora usando IA de forma simple","Lo que muchos entienden mal sobre la IA","Una historia local sobre IA para pequeñas empresas","Antes de ignorar esta tendencia, mira esto","La prueba de 3 segundos para entender la oportunidad","Por qué los creadores hablan de este tema","La forma segura de probar esta idea","El detalle pequeño que cambia todo","Qué viene después en esta tendencia"][i]||"Idea recomendada"}</strong><p>Promesa clara, útil y responsable para el público del canal.</p><div class="style-meta"><span>Curiosidad ${x.curiosity}</span><span>Nivel viral ${x.viral_level}</span><span>Monetización ${x.monetization}</span><span>Retención ${x.retention}</span></div><button class="ghost-btn" data-workflow-action="choose-idea" data-idea-id="${x.id}">Elegir idea</button></article>`).join("")}
function hooksFlujo(){return estadoFlujo.hooks.map((x,i)=>`<div class="hook-card ${estadoFlujo.hookElegido?.id===x.id?"selected":""}"><strong>${datos.hooks[i]?.[0]||"Hook recomendado"}</strong><span>${x.score}/100</span><small>Alta retención esperada</small><button class="ghost-btn" data-workflow-action="choose-hook" data-hook-id="${x.id}">Seleccionar hook</button></div>`).join("")}
function pantallaFlujo(){return `${ayuda("mvp-workflow")}${barra()}${formCanal()}${estadoFlujo.canal?`<article class="card"><span class="eyebrow">Paso 2</span><h3>Auditar oportunidad</h3>${estadoFlujo.oportunidad?`<div class="grid four"><article class="metric-card"><small>Nivel de oportunidad</small><span class="metric-value">${estadoFlujo.oportunidad.opportunity_score}</span></article><article class="metric-card"><small>Competencia</small><span class="metric-value">${estadoFlujo.oportunidad.competition}</span></article><article class="metric-card"><small>Potencial</small><span class="metric-value">${estadoFlujo.oportunidad.potential}</span></article><article class="metric-card"><small>Decisión</small><span class="metric-value">${estadoFlujo.decisionEjecutiva?.decision||"Pendiente"}</span></article></div><div class="ready-card card"><span class="eyebrow">Director Ejecutivo IA</span><h3>${estadoFlujo.decisionEjecutiva?.decision||"Evaluando"}</h3><p>${estadoFlujo.decisionEjecutiva?.rationale||"La IA decide si vale la pena producir antes de gastar recursos."}</p></div>`:`<p class="muted">El Director Ejecutivo IA auditará popularidad, competencia, costo, ROI y riesgo antes de continuar.</p>`}<button class="primary-btn" data-workflow-action="analyze-opportunity">Auditar oportunidad</button></article>`:""}${estadoFlujo.oportunidad?`<article class="card"><span class="eyebrow">Pasos 3 y 4</span><h3>Generar y elegir idea</h3>${estadoFlujo.ideas.length?`<div class="workflow-idea-grid">${ideasFlujo()}</div>`:`<p class="muted">Solo se generan ideas cuando la decisión ejecutiva es PRODUCIR.</p>`}<button class="primary-btn" data-workflow-action="generate-ideas">Generar 10 ideas</button></article>`:""}${estadoFlujo.ideaElegida?`<article class="card"><span class="eyebrow">Paso 5</span><h3>Generar hook</h3>${estadoFlujo.hooks.length?`<div class="hook-stack">${hooksFlujo()}</div>`:`<p class="muted">Genera 5 opciones de inicio para la idea elegida.</p>`}<button class="primary-btn" data-workflow-action="generate-hooks">Generar hooks</button></article>`:""}${estadoFlujo.hookElegido?`<article class="card"><span class="eyebrow">Pasos 6 y 7</span><h3>Estrategia narrativa y storyboard</h3>${estadoFlujo.historia?`${historia()}<div class="scene-grid">${[1,2,3,4].map(n=>`<article class="scene-card"><span>Escena ${n}</span><strong>${["Problema principal","Ejemplo local","Comparación simple","Cierre con llamada a la acción"][n-1]}</strong><p>${["Abrimos con una pregunta clara.","Mostramos la idea con un caso concreto.","Explicamos el beneficio sin exagerar.","Invitamos a conversar de forma responsable."][n-1]}</p><small>Subtítulo breve y claro.</small></article>`).join("")}</div>`:`<p class="muted">Genera objetivo, narrador, personaje, escenario, tono, duración, estilo y storyboard.</p>`}<button class="primary-btn" data-workflow-action="generate-story">Generar estrategia narrativa</button></article>`:""}${estadoFlujo.historia?`<article class="card"><span class="eyebrow">Paso 8</span><h3>Plan de producción</h3>${estadoFlujo.plan?plan():`<p class="muted">Define narrador, voz, formato, música, iluminación, cámara, color y ritmo.</p>`}<button class="primary-btn" data-workflow-action="generate-production-plan">Generar plan de producción</button></article>`:""}${estadoFlujo.plan?`<article class="card ready-card"><span class="eyebrow">Paso 9</span><h3>${estadoFlujo.listo?"Todo está listo para generar el video.":"Listo para generar el video"}</h3><p>No se generará video todavía. El proyecto queda preparado para una fase futura.</p>${estadoFlujo.listo?badge("Listo","ok"):`<button class="primary-btn" data-workflow-action="ready-to-generate">Marcar como listo</button>`}</article>`:""}`}
const pageTitle=document.getElementById("pageTitle"),sideNav=document.getElementById("sideNav"),toast=document.getElementById("toast"),sidebar=document.querySelector(".sidebar"),view=document.getElementById("view");
function renderScreen(id){const normal=alias[id]||id||"inicio";const p=pantallas.find(x=>x.id===normal)||pantallas[0];pageTitle.textContent=p.label;document.querySelectorAll(".nav-link").forEach(a=>a.classList.toggle("active",a.dataset.id===p.id));view.innerHTML=p.id==="inicio"?inicio():p.id==="mvp-workflow"?pantallaFlujo():pantalla(p.id);bindActions()}
function bindActions(){document.querySelectorAll("[data-soon]").forEach(b=>b.addEventListener("click",()=>{toast.textContent=UI.pronto;toast.classList.add("show");setTimeout(()=>toast.classList.remove("show"),1500)}));document.querySelectorAll("[data-go]").forEach(b=>b.addEventListener("click",()=>location.hash=b.dataset.go));document.querySelectorAll("[data-workflow-action]").forEach(b=>b.addEventListener("click",()=>accionFlujo(b.dataset.workflowAction,{ideaId:b.dataset.ideaId,hookId:b.dataset.hookId})));document.querySelectorAll("[data-project-action]").forEach(b=>b.addEventListener("click",()=>accionProyecto(b.dataset.projectAction,b.dataset.projectId)));document.querySelectorAll("[data-production-action]").forEach(b=>b.addEventListener("click",()=>accionProduccionIA(b.dataset.productionAction,b.dataset.jobId)));const dz=document.getElementById("projectDropzone");if(dz){dz.addEventListener("click",()=>accionProyecto("fake-docs"));dz.addEventListener("dragover",e=>{e.preventDefault();dz.classList.add("dragging")});dz.addEventListener("dragleave",()=>dz.classList.remove("dragging"));dz.addEventListener("drop",e=>{e.preventDefault();dz.classList.remove("dragging");accionProyecto("fake-docs")})}}
function buildNav(){sideNav.innerHTML=categorias.map(([nombre,items])=>`<div class="nav-group"><span>${nombre}</span>${items.map(([id,label,icon,kpi])=>`<a class="nav-link" href="#${id}" data-id="${id}" title="${label}"><span class="nav-icon">${icon}</span><span>${label}</span><small class="nav-kpi">${kpi}</small></a>`).join("")}</div>`).join("")}
function route(){renderScreen(location.hash.replace("#","")||"inicio");sidebar.classList.remove("open")}
document.getElementById("menuToggle").addEventListener("click",()=>sidebar.classList.toggle("open"));window.addEventListener("hashchange",route);buildNav();route();








